import { useState } from 'react';
import { Link, useParams, useNavigate } from 'react-router-dom';
import SEO from './SEO';
import { authAPI } from '../services/api';

const ResetPassword = ({ theme, toggleTheme }) => {
    const { token } = useParams();
    const navigate = useNavigate();
    const [formData, setFormData] = useState({ password: '', confirmPassword: '' });
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [errors, setErrors] = useState({});
    const [success, setSuccess] = useState(false);

    const validate = () => {
        const newErrors = {};
        if (!formData.password) newErrors.password = 'Password is required';
        else if (formData.password.length < 6) newErrors.password = 'Password must be at least 6 characters';
        if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = 'Passwords do not match';
        return newErrors;
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        const validationErrors = validate();
        if (Object.keys(validationErrors).length > 0) { setErrors(validationErrors); return; }
        setLoading(true);
        try {
            await authAPI.resetPassword(token, formData.password);
            setSuccess(true);
            setTimeout(() => navigate('/login'), 3000);
        } catch (error) { setErrors({ global: error.message || 'Invalid or expired token. Please try again.' }); }
        finally { setLoading(false); }
    };

    return (
        <>
            <SEO title="Create New Password | CodeNexus Studio" description="Create a new password for your CodeNexus Studio account." canonical={`https://codenexusstudio.vercel.app/reset-password/${token}`} />

            <div className="min-h-screen flex flex-col bg-[var(--bg-dark)] relative overflow-hidden">
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[550px] h-[550px] -top-[15%] -left-[12%] bg-[radial-gradient(circle,var(--primary-glow),transparent_70%)]"></div>
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[480px] h-[480px] -bottom-[10%] -right-[10%] bg-[radial-gradient(circle,rgba(168,85,247,0.35),transparent_70%)] [animation-delay:-6s]"></div>

                <header className="flex items-center justify-between py-5 px-10 max-sm:px-5 relative z-10">
                    <Link to="/" className="font-['Outfit'] text-2xl font-extrabold text-[var(--text-main)] no-underline tracking-[-0.5px] transition-opacity duration-300 hover:opacity-80">
                        Code<span className="bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] bg-clip-text [-webkit-text-fill-color:transparent]">Nexus</span>.
                    </Link>
                    <button className="bg-[rgba(255,255,255,0.05)] border border-[var(--glass-border)] rounded-full w-10 h-10 text-[1.1rem] cursor-pointer transition-all duration-300 flex items-center justify-center color-[var(--text-main)] hover:scale-105 hover:bg-[rgba(255,255,255,0.1)] hover:border-[var(--primary)]" onClick={toggleTheme} aria-label="Toggle theme">
                        {theme === 'light' ? '🌞' : '🌙'}
                    </button>
                </header>

                <main className="flex-1 flex items-center justify-center py-8 px-4 relative z-[5]">
                    <div className="bg-[var(--glass-bg)] border border-[var(--glass-border)] backdrop-blur-[20px] rounded-3xl p-11 max-sm:p-8 w-full max-w-[440px] shadow-[0_8px_32px_rgba(0,0,0,0.35),inset_0_0_0_1px_var(--glass-border)] animate-[cardFadeIn_0.6s_cubic-bezier(0.22,1,0.36,1)]">
                        <div className="w-[60px] h-[60px] rounded-2xl bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] flex items-center justify-center mx-auto mb-6 shadow-[0_8px_24px_var(--primary-glow)]">
                            <svg className="w-7 h-7 text-white" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <rect x="3" y="11" width="18" height="11" rx="2" ry="2" stroke="currentColor" strokeWidth="2" />
                                <path d="M7 11V7a5 5 0 0 1 10 0v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                            </svg>
                        </div>

                        <h1 className="text-[1.85rem] max-sm:text-[1.6rem] font-extrabold text-center text-[var(--text-main)] mb-1 tracking-[-0.5px]">Create New Password</h1>
                        <p className="text-center color-[var(--text-muted)] text-[0.95rem] mb-8">Your new password must be different from previously used passwords.</p>

                        {success ? (
                            <div className="text-center mb-5">
                                <p className="text-emerald-500 mb-4">Password reset successful! Redirecting to login...</p>
                            </div>
                        ) : (
                            <form onSubmit={handleSubmit} className="flex flex-col gap-5" noValidate>
                                {errors.global && (
                                    <div className="p-3 mb-4 bg-[rgba(239,68,68,0.1)] text-red-500 rounded-lg text-center text-sm border border-[rgba(239,68,68,0.2)]">{errors.global}</div>
                                )}

                                <div className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                    <label htmlFor="password" className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">New Password</label>
                                    <div className="relative flex items-center">
                                        <span className="absolute left-3.5 flex items-center text-[var(--text-muted)] pointer-events-none">
                                            <svg className="w-[17px] h-[17px]" viewBox="0 0 24 24" fill="none"><rect x="3" y="11" width="18" height="11" rx="2" ry="2" stroke="currentColor" strokeWidth="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
                                        </span>
                                        <input id="password" type={showPassword ? 'text' : 'password'} name="password" placeholder="Enter new password" value={formData.password} onChange={handleChange} className={`w-full py-3 pr-4 pl-11 bg-[rgba(255,255,255,0.05)] border-2 ${errors.password ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.95rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                        <button type="button" className="absolute right-3 bg-none border-none cursor-pointer text-[var(--text-muted)] p-1 flex items-center transition-colors duration-300 hover:text-[var(--primary)]" onClick={() => setShowPassword(p => !p)} aria-label="Toggle password visibility">
                                            {showPassword ? <svg className="w-[17px] h-[17px]" viewBox="0 0 24 24" fill="none"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><line x1="1" y1="1" x2="23" y2="23" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg> : <svg className="w-[17px] h-[17px]" viewBox="0 0 24 24" fill="none"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><circle cx="12" cy="12" r="3" stroke="currentColor" strokeWidth="2" /></svg>}
                                        </button>
                                    </div>
                                    {errors.password && <span className="text-[0.8rem] text-red-400 pl-0.5">{errors.password}</span>}
                                </div>

                                <div className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                    <label htmlFor="confirmPassword" className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">Confirm Password</label>
                                    <div className="relative flex items-center">
                                        <span className="absolute left-3.5 flex items-center text-[var(--text-muted)] pointer-events-none">
                                            <svg className="w-[17px] h-[17px]" viewBox="0 0 24 24" fill="none"><rect x="3" y="11" width="18" height="11" rx="2" ry="2" stroke="currentColor" strokeWidth="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
                                        </span>
                                        <input id="confirmPassword" type={showPassword ? 'text' : 'password'} name="confirmPassword" placeholder="Confirm new password" value={formData.confirmPassword} onChange={handleChange} className={`w-full py-3 pr-4 pl-11 bg-[rgba(255,255,255,0.05)] border-2 ${errors.confirmPassword ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.95rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                    </div>
                                    {errors.confirmPassword && <span className="text-[0.8rem] text-red-400 pl-0.5">{errors.confirmPassword}</span>}
                                </div>

                                <button type="submit" className="mt-2 py-[0.85rem] px-6 bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] text-white border-none rounded-xl text-base font-bold font-['Outfit'] cursor-pointer flex items-center justify-center gap-2 transition-all duration-250 shadow-[0_4px_20px_var(--primary-glow)] hover:not(:disabled):opacity-90 hover:not(:disabled):-translate-y-0.5 hover:not(:disabled):shadow-[0_8px_28px_var(--primary-glow)] disabled:opacity-70 disabled:cursor-not-allowed group" disabled={loading}>
                                    {loading ? <span className="w-[22px] h-[22px] border-4 border-white/30 border-t-white rounded-full animate-spin"></span> : <>Reset Password <span className="inline-block transition-transform duration-300 group-hover:translate-x-1">→</span></>}
                                </button>
                            </form>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

export default ResetPassword;
